const task = $('Fetch Latest Queued Task').first().json;
const response = $input.first().json;

const organic = Array.isArray(response.organic) ? response.organic : [];

function normalizeUrl(rawUrl) {
  const value = String(rawUrl || '').trim();

  if (!value.startsWith('http://') && !value.startsWith('https://')) {
    return null;
  }

  // 去掉 ? 后所有查询参数，以及 # 后锚点
  const withoutQuery = value.split('?')[0].split('#')[0];

  // 提取 protocol + domain + pathname
  const match = withoutQuery.match(/^(https?:\/\/[^/]+)(\/.*)?$/i);

  if (!match) {
    return null;
  }

  const base = match[1];
  let path = match[2] || '/';

  // 首页统一为 /
  if (path === '') {
    path = '/';
  }

  return `${base}${path}`;
}

function cleanCompanyName(title) {
  const text = String(title || '').trim();

  const parts = text
    .split(/\s+[|–—-]\s+/)
    .map((item) => item.trim())
    .filter(Boolean);

  return parts[0] || text || null;
}

const candidates = [];

for (const result of organic) {
  const originalUrl = result.link || '';
  const cleanWebsite = normalizeUrl(originalUrl);

  if (!cleanWebsite) {
    continue;
  }

  candidates.push({
    json: {
      task_id: task.task_id,
      product_id: task.product_id,
      company_name: cleanCompanyName(result.title),
      website: cleanWebsite,
      country: task.country,
      industry: task.industry,
      source: 'serper_google',
      source_url: originalUrl,
      search_query: task.search_query,
      page_title: result.title || null,
      page_snippet: result.snippet || null,
      raw_data: result,
    },
  });
}

return candidates;
